B.X7=s(["The beginning of the missed approach","The start of the final approach segment","The runway threshold","The IAF position"],t.s)
B.a92=new A.a0(-271,B.ay,641,"The FAF (Final Approach Fix) marks:",B.X7,1,B.w,null,null,null)
