B.tr=new A.bM("reading_5","SID/STAR Prosed\xfcrleri","Kalk\u0131\u015f ve var\u0131\u015f prosed\xfcr belgelerini okuma","reading","\ud83d\uddfa\ufe0f",B.X9)
B.UT=new A.J(B.S,"Kaza raporlar\u0131 karma\u015f\u0131k metinlerdir","Havac\u0131l\u0131k kaza soru\u015fturma raporlar\u0131 (ICAO Ek 13 standartlar\u0131na g\xf6re haz\u0131rlananlar gibi) havac\u0131l\u0131k \u0130ngilizcesi s\u0131navlar\u0131nda s\u0131nanan en karma\u015f\u0131k metinlerdendir.\n\nTeknik terminoloji, edilgen yap\u0131lar, dolayl\u0131 anlat\u0131m ve ko\u015ful \xe7\u0131kar\u0131mlar\u0131n\u0131 tek bir belgede bir araya getirirler.",null,null,null)
B.Rk=new A.J(B.A,"\ud83d\udccb Rapor Yap\u0131s\u0131","Standart bir kaza raporu \u015funlar\u0131 i\xe7erir:\n1. **\xd6zet (Synopsis)** \u2014 kazan\u0131n k\u0131sa \xf6zeti\n2. **Olgusal bilgi** \u2014 u\xe7ak, m\xfcrettebat, hava durumu, havaliman\u0131 verileri\n3. **Analiz** \u2014 ne oldu\u011fu ve neden (neden zinciri)\n4. **Bulgular** \u2014 tespit edilen olgular\n5. **Neden** \u2014 muhtemel neden(ler)\n6. **G\xfcvenlik \xf6nerileri** \u2014 neyin de\u011fi\u015fmesi gerekti\u011fi\n\nS\u0131nav sorular\u0131 genellikle **Olgusal Bilgi** ve **Analiz** b\xf6l\xfcmlerini hedefler.",null,null,null)
B.T8=new A.J(B.A,"\ud83d\udd0d Kritik Okuma Becerileri","Kaza raporu pasajlar\u0131 i\xe7in:\n\u2022 **S\u0131ralama kelimeleri**: prior to, during, following, subsequently, as a result\n\u2022 **Nedensellik dili**: due to, caused by, attributed to, led to, resulted in\n\u2022 **Bulgu ile \xd6neri** aras\u0131ndaki fark: bulgular olgulard\u0131r; \xf6neriler tavsiyedir\n\u2022 **Contributing factor** \u2260 **Probable cause**: katk\u0131da bulunan fakt\xf6rler durumu a\u011f\u0131rla\u015ft\u0131r\u0131r; muhtemel neden birincil sebeptir",null,null,null)
B.Mi=new A.al("The accident was attributed to the crew's failure to monitor fuel quantity during the extended hold.","Kaza, ekibin uzun s\xfcren bekleme s\u0131ras\u0131nda yak\u0131t miktar\u0131n\u0131 izlememesine ba\u011fland\u0131.","attributed to")
B.N3=new A.al("A contributing factor was the inadequate crew resource management training.","Katk\u0131da bulunan bir fakt\xf6r yetersiz ekip kaynak y\xf6netimi e\u011fitimiydi.","contributing factor")
B.WV=s([B.Mi,B.N3],t.l)
B.Ub=new A.J(B.T,"Rapor Dili \xd6rnekleri",null,B.WV,null,null)
B.Ug=new A.J(B.am,"\u2708\ufe0f \u0130leri Okuma Stratejisi","\xdc\xe7 okuma y\xf6ntemi:\n1. **Birinci okuma**: konu ve yap\u0131y\u0131 taramak i\xe7in (30 saniye)\n2. **Soruyu oku**: tam olarak neyin soruldu\u011funu anla\n3. **\u0130kinci okuma**: yaln\u0131zca ilgili paragrafa odaklan\n\nBellekten yan\u0131t verme \u2014 her zaman metinde do\u011frula. \u0130leri d\xfczey sorularda \xe7o\u011funlukla pasajdaki kelimelerin yanl\u0131\u015f ba\u011flamda kullan\u0131ld\u0131\u011f\u0131 **mant\u0131kl\u0131 ama yanl\u0131\u015f** se\xe7enekler bulunur.",null,null,null)
B.Xc=s(["To start the engine for the first time","To test the fuel system","To increase engine speed","To test the electrical system"],t.s)
