B.Ys=s([B.a9d,B.a8v,B.a83],t.C)
B.RB=new A.J(B.R,"Pratik Sorular",'"Wet motoring the engine is necessary to test the fuel system. When an engine is wet motored, the two ignition systems are turned OFF and the starter is engaged to turn the HP rotor to 15%-20% N2. At N2 = 15%, the HP fuel shutoff valve control lever is moved to ON and the engine exhaust nozzle is carefully monitored for any sign of fuel."',null,null,B.Ys)
B.a_9=s([B.UT,B.Rk,B.T8,B.Ub,B.Ug,B.RB],t.q)
B.tF=new A.bM("reading_2","Kaza Raporu Analizi","\u0130leri okuma anlama","reading","\ud83d\udcd1",B.a_9)
B.Tc=new A.J(B.S,"D\xfc\u015f\xfck g\xf6r\xfc\u015f operasyonlar\u0131 kesin dil gerektirir","CAT II ve CAT III yakla\u015fmalar\u0131 otomatik indi\u015f sistemleri kullan\u0131larak \xe7ok d\xfc\u015f\xfck g\xf6r\xfc\u015f ko\u015fullar\u0131nda ger\xe7ekle\u015ftirilir. Bu prosed\xfcrlerdeki ifadeler, uyar\u0131lar ve s\xf6zl\xfc bildirimler havac\u0131l\u0131k \u0130ngilizcesinin en kesin tan\u0131ml\u0131 ifadeleri aras\u0131ndad\u0131r.\n\nBu alandaki c\xfcmle tamamlama sorular\u0131, prosed\xfcr terminolojisinin tam bilgisini gerektirir.",null,null,null)
B.SW=new A.J(B.A,"\ud83c\udf2b\ufe0f ILS Kategorileri","**CAT I** \u2014 DH \u2265200ft, RVR \u2265550m (standard ILS)\n**CAT II** \u2014 DH 100\u2013200ft, RVR \u2265300m (needs specific aircraft/crew cert)\n**CAT IIIA** \u2014 DH <100ft OR no DH, RVR \u2265200m\n**CAT IIIB** \u2014 DH <50ft OR no DH, RVR 50\u2013200m\n**CAT IIIC** \u2014 No DH, No RVR limit (still not in service)\n\n**LVP** \u2014 Low Visibility Procedures (activated by airport when RVR <600m)\n**LVT** \u2014 Low Visibility Takeoff",null,null,null)
B.UY=new A.J(B.A,"\ud83d\udce2 CAT III S\xf6zl\xfc Bildirimleri",'Standart CAT III yakla\u015fma s\xf6zl\xfc bildirimleri (s\u0131rayla):\n1. "**Localizer alive**" \u2014 ILS localizer yakaland\u0131\n2. "**Glide slope alive**" \u2014 dikey rehberlik yakaland\u0131\n3. "**Land 3**" \u2014 otomatik indi\u015f modu onayland\u0131 (A320 ailesi)\n4. "**1,000 feet**" \u2014 standart kontrol irtifas\u0131\n5. "**500 feet**" \u2014 istikrar kontrol\xfc\n6. "**100 feet**" \u2014 g\xf6rsel veya etrafta d\xf6n\xfc\u015f karar\u0131\n7. "**50, 40, 30, 20, 10**" \u2014 radyo altimetre \xe7a\u011fr\u0131lar\u0131\n8. "**Touchdown**" \u2192 "**Decelerate**" \u2192 "**Vacate**"',null,null,null)
B.Mv=new A.al("During LVP, ground movement must be strictly controlled to prevent runway incursion.","LVP s\u0131ras\u0131nda pist ihlalini \xf6nlemek i\xe7in yer hareketi kesinlikle kontrol edilmelidir.","LVP")
B.Mb=new A.al("At Decision Height, if the required visual reference is not established, a go-around must be executed.","Karar \u0130rtifas\u0131nda, gerekli g\xf6rsel referans sa\u011flanamazsa t\u0131rman\u0131\u015f prosed\xfcr\xfc uygulanmal\u0131d\u0131r.","Decision Height")
B.XN=s([B.Mv,B.Mb],t.l)
B.Se=new A.J(B.T,"CAT III Tamamlama \xd6rnekleri",null,B.XN,null,null)
B.Sk=new A.J(B.am,"\u2708\ufe0f S\u0131nav \u0130pucu",'S\u0131navlar i\xe7in CAT II/III temel ayr\u0131mlar\u0131:\n\u2022 **DH** = Karar \u0130rtifas\u0131 (radyo altimetre tabanl\u0131, CAT II/III)\n\u2022 **DA** = Karar Y\xfcksekli\u011fi (barometre tabanl\u0131, CAT I)\n\u2022 **RVR** = Pist G\xf6r\xfc\u015f Mesafesi (transmissometre ile \xf6l\xe7\xfcl\xfcr)\n\u2022 Otomatik taksi/fren kullan\u0131labilirse CAT IIIB yakla\u015fma **Karar \u0130rtifas\u0131 olmadan** yap\u0131labilir\n\u2022 LVP, d\xfc\u015f\xfck g\xf6r\xfc\u015fl\xfc kalk\u0131\u015flar\u0131 otomatik olarak iptal etmez \u2014 ayr\u0131 LVT minimumlari vard\u0131r\n\u2022 CAT III i\xe7in "zorunlu g\xf6rsel referans" CAT I\'e g\xf6re **daha azd\u0131r** (yaln\u0131zca pist kenar \u0131\u015f\u0131klar\u0131 yeterli olabilir)',null,null,null)
