B.TU=new A.J(B.S,"ADs are mandatory safety compliance documents","U\xe7u\u015fa Elveri\u015flilik Direktifi (AD), belirli bir u\xe7ak tipindeki g\xfcvenli olmayan bir durumu gidermek amac\u0131yla sivil havac\u0131l\u0131k otoritesi taraf\u0131ndan zorunlu eylem gerektiren yasal ba\u011flay\u0131c\u0131 bir belgedir. Uyumsuzluk yasad\u0131\u015f\u0131d\u0131r ve i\u015fletme sertifikas\u0131n\u0131n ask\u0131ya al\u0131nmas\u0131na yol a\xe7abilir.\n\nAD dili havac\u0131l\u0131ktaki en kesin d\xfczenleyici dildir \u2014 her kelimenin yasal a\u011f\u0131rl\u0131\u011f\u0131 vard\u0131r.",null,null,null)
B.Tm=new A.J(B.A,"\ud83d\udcdc AD Yap\u0131s\u0131",'Tipik bir AD \u015funlar\u0131 i\xe7erir:\n1. **Uygulanabilirlik** \u2014 hangi u\xe7ak/motor/par\xe7alar etkileniyor\n2. **G\xfcvensiz durum** \u2014 \xe7\xf6z\xfclecek tehlike\n3. **Gerekli eylem** \u2014 ne yap\u0131lmas\u0131 gerekiyor\n4. **Uyumluluk s\xfcresi** \u2014 ne zamana kadar yap\u0131lmal\u0131 (\xf6r. "50 u\xe7u\u015f saati i\xe7inde")\n5. **Y\xf6ntem** \u2014 nas\u0131l uyulur (servis b\xfclteni, \xf6zel prosed\xfcr)\n6. **Alternatif Uyumluluk Y\xf6ntemi (AMOC)** \u2014 onaylanm\u0131\u015f alternatif\n7. **Maliyetler** \u2014 tahmini uyumluluk maliyeti',null,null,null)
B.UX=new A.J(B.A,"\u26a0\ufe0f Uyumluluk S\xfcresi Dili",'**"Within 50 flight hours after the effective date"** \u2014 must be done before 50 more hours\n**"At the next scheduled maintenance"** \u2014 at next A/B/C check\n**"Before further flight"** \u2014 aircraft must not fly until complied with\n**"At first opportunity"** \u2014 as soon as practical (not as urgent as "before further flight")\n**"Repetitive inspection every 200 FH"** \u2014 not a one-time action; must be repeated\n**"Terminating action"** \u2014 permanently satisfies the AD (no more repetitive checks needed)',null,null,null)
B.M6=new A.al("This AD requires repetitive inspections of the fuselage skin every 500 flight cycles.","Bu AD, her 500 u\xe7u\u015f \xe7evriminde g\xf6vde kaplamas\u0131n\u0131n tekrarl\u0131 denetimlerini gerektirmektedir.","repetitive inspections")
B.Nc=new A.al("The applicability of this AD extends to all Boeing 737-800 aircraft with serial numbers 35201 through 41234.","Bu AD'nin uygulanabilirli\u011fi, 35201 ile 41234 aras\u0131ndaki seri numaralar\u0131na sahip t\xfcm Boeing 737-800 u\xe7aklar\u0131n\u0131 kapsamaktad\u0131r.","applicability")
B.M8=new A.al("Compliance is required before further flight after the effective date.","Y\xfcr\xfcrl\xfck tarihinden sonra daha fazla u\xe7u\u015ftan \xf6nce uyum zorunludur.","before further flight")
B.a1S=s([B.M6,B.Nc,B.M8],t.l)
B.U4=new A.J(B.T,"AD Dili \xd6rnekleri",null,B.a1S,null,null)
B.Ut=new A.J(B.am,"\u2708\ufe0f \u0130leri Okuma Stratejisi",'AD okuma anlama sorular\u0131 i\xe7in:\n\u2022 **Uygulanabilirlik** b\xf6l\xfcm\xfc hangi u\xe7aklar\u0131n etkilendi\u011fini s\xf6yler \u2014 bunu \xf6nce kontrol edin\n\u2022 "**Before further flight**" = en acil uyumluluk s\xfcresi \u2014 u\xe7ak YER\'DE KALMALIDIR\n\u2022 "**Terminating action**" = bir kez yap\u0131ld\u0131\u011f\u0131nda tekrar edici denetim gerekmez\n\u2022 **AMOC** = alternatif uyumluluk y\xf6ntemi \u2014 otorite taraf\u0131ndan onaylanmal\u0131d\u0131r\n\u2022 "**At the next scheduled**" "iste\u011fe ba\u011fl\u0131" anlam\u0131na gelmez \u2014 o noktada zorunludur\n\u2022 Tarihlere dikkat edin: "after the effective date" ile "from the date of manufacture"',null,null,null)
B.a1I=s(["All Airbus A320 variants","A320-200 with serial numbers 3001\u20135500","A320-200 manufactured after the effective date","All Airbus narrowbody aircraft"],t.s)
B.a7k=new A.a0(-310,B.ay,650,"Which aircraft are affected by this AD?",B.a1I,1,B.C,null,null,null)
B.a1X=s(["Every 100 flight cycles","Once only","Every 500 flight cycles","At every annual check"],t.s)
B.a7F=new A.a0(-311,B.ay,651,"How often must the repetitive inspection be performed?",B.a1X,2,B.C,null,null,null)
B.XF=s(["Performing 10 consecutive inspections with no findings","Replacing the frame assembly with Part Number A320-FR-9902","Operating the aircraft for 5,000 flight cycles","Obtaining an AMOC from the authority"],t.s)
